questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Given values ===== */
N_turns: if set=1 then 200 else if set=2 then 500 else 300;
r_cm:    if set=1 then 2   else if set=2 then 1.5 else 3;
ell_cm:  if set=1 then 20  else if set=2 then 10  else 30;
I_val:   if set=1 then 1.5 else if set=2 then 0.8 else 2.0;

/* ===== Derived values ===== */
r_val:   r_cm/100;
ell_val: ell_cm/100;
A_val:   float(%pi*r_val^2);
mu0:     4*%pi/10^7;
L_val:   float(mu0*N_turns^2*A_val/ell_val);
W_val:   float(0.5*L_val*I_val^2);

/* Display-friendly values */
A_disp: float(A_val);

/* ===== Common errors for debug task ===== */
/* Wrong formula: L = mu0*N*A/ell (used N instead of N²) */
wrong_L:    float(mu0*N_turns*A_val/ell_val);
wrong_L_mH: float(wrong_L*1000);

/* ===== Teacher answers ===== */
ta1: float(L_val*1000);   /* L in mH */
ta2: float(W_val*1000);   /* W in mJ */

/* Part (c) MCQ: Debug task — which wrong formula was used? */
ta3: [[1, true,  "L = &mu;&#8320;NA/&ell; &mdash; they used N instead of N&sup2; in the formula"],
      [2, false, "L = &mu;&#8320;N&sup2;&ell;/A &mdash; they swapped the area and length"],
      [3, false, "L = &mu;&#8320;N&sup2;A&middot;&ell; &mdash; they multiplied by &ell; instead of dividing"],
      [4, false, "L = &mu;&#8320;A/(N&sup2;&ell;) &mdash; they put N&sup2; in the denominator"]];
ta3_correct: 1;

/* Part (d) MCQ: Energy scaling when current doubles */
ta4: [[1, false, "The energy doubles (&times;2)"],
      [2, true,  "The energy quadruples (&times;4) &mdash; energy is proportional to I&sup2;"],
      [3, false, "The energy stays the same &mdash; inductance hasn&rsquo;t changed"],
      [4, false, "The energy increases by a factor of 8"]];
ta4_correct: 2;

feedbackvariables.text:
sa1_float: float(ans1);
ref1_float: float(ta1);
/* Order-of-magnitude check */
prt1_oom_ok: if (abs(ref1_float) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and (abs(sa1_float/ref1_float - 10) < 1.5 or abs(sa1_float/ref1_float - 0.1) < 0.015)) then true else false;

sa2_float: float(ans2);
ref2_float: float(ta2);
/* Order-of-magnitude check */
prt2_oom_ok: if (abs(ref2_float) > 1.0e-30 and abs(sa2_float) > 1.0e-30 and (abs(sa2_float/ref2_float - 10) < 1.5 or abs(sa2_float/ref2_float - 0.1) < 0.015)) then true else false;
